#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim)
{
    int i, j, k;
    int offset, num_blocks;

    num_blocks = matrix_dim / BLOCK_SIZE;
    if (matrix_dim % BLOCK_SIZE != 0) num_blocks++;

    float *shadow = (float *)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
    float *peri_row = (float *)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);
    float *peri_col = (float *)malloc(sizeof(float) * BLOCK_SIZE * BLOCK_SIZE);

    for (offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        int block_size = BLOCK_SIZE;
        if (offset + BLOCK_SIZE > matrix_dim)
            block_size = matrix_dim - offset;

        // lud_diagonal equivalent
        {
            int tx;
#pragma omp parallel for private(tx, i, j) shared(m, shadow, matrix_dim, offset, block_size)
            for (tx = 0; tx < block_size; tx++) {
                int array_offset = offset*matrix_dim + offset;
                for (i = 0; i < block_size; i++) {
                    shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                    array_offset += matrix_dim;
                }
            }

            for (i = 0; i < block_size - 1; i++) {
#pragma omp parallel for private(tx, j) shared(shadow, i, block_size)
                for (tx = i + 1; tx < block_size; tx++) {
                    for (j = 0; j < i; j++)
                        shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                    shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
                }
#pragma omp barrier

#pragma omp parallel for private(tx, j) shared(shadow, i, block_size)
                for (tx = i + 1; tx < block_size; tx++) {
                    for (j = 0; j < i + 1; j++)
                        shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
                }
#pragma omp barrier
            }

            int array_offset = (offset + 1)*matrix_dim + offset;
#pragma omp parallel for private(tx) shared(m, shadow, block_size, array_offset)
            for (tx = 0; tx < block_size; tx++) {
                for (i = 1; i < block_size; i++) {
                    m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }
        }

        // lud_perimeter equivalent
        if (offset + block_size < matrix_dim) {
            int bx, tx, i, j, array_offset, idx;
            int num_blocks_remaining = (matrix_dim - offset) / block_size - 1;
            if ((matrix_dim - offset) % block_size != 0) num_blocks_remaining++;

#pragma omp parallel private(bx, tx, i, j, array_offset, idx) shared(m, shadow, peri_row, peri_col, matrix_dim, offset, block_size, num_blocks_remaining)
            {
                bx = omp_get_thread_num();
                tx = bx % (block_size * 2);
                bx = bx / (block_size * 2);

                int total_threads = omp_get_num_threads();

                // Because OpenMP doesn't allow launching kernel with more threads than set,
                // use manual parallel for loops instead of mapping tx to threads.

                // So we use a parallel for to cover all perimeter threads:
                // We'll parallelize with 2*block_size threads per perimeter block as in original

                // Instead, better to write explicit loops here:

#pragma omp for schedule(static)
                for (int tid = 0; tid < 2 * block_size * num_blocks_remaining; tid++) {
                    int bx_local = tid / (2 * block_size);
                    int tx_local = tid % (2 * block_size);

                    if (tx_local < block_size) {
                        idx = tx_local;
                        array_offset = offset*matrix_dim + offset;
                        for (i = 0; i < block_size / 2; i++) {
                            shadow[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }

                        array_offset = offset*matrix_dim + offset;
                        for (i = 0; i < block_size; i++) {
                            peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx_local + 1)*block_size + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx_local - block_size;

                        array_offset = (offset + block_size / 2)*matrix_dim + offset;
                        for (i = block_size / 2; i < block_size; i++) {
                            shadow[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }

                        array_offset = (offset + (bx_local + 1)*block_size)*matrix_dim + offset;
                        for (i = 0; i < block_size; i++) {
                            peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }
#pragma omp barrier

#pragma omp for schedule(static)
                for (int tid = 0; tid < 2 * block_size * num_blocks_remaining; tid++) {
                    int bx_local = tid / (2 * block_size);
                    int tx_local = tid % (2 * block_size);

                    if (tx_local < block_size) {
                        idx = tx_local;
                        for (i = 1; i < block_size; i++) {
                            for (j = 0; j < i; j++) {
                                peri_row[i * BLOCK_SIZE + idx] -= shadow[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                            }
                        }
                    } else {
                        idx = tx_local - block_size;
                        for (i = 0; i < block_size; i++) {
                            for (j = 0; j < i; j++) {
                                peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                            }
                            peri_col[idx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
                        }
                    }
                }
#pragma omp barrier

#pragma omp for schedule(static)
                for (int tid = 0; tid < 2 * block_size * num_blocks_remaining; tid++) {
                    int bx_local = tid / (2 * block_size);
                    int tx_local = tid % (2 * block_size);
                    int array_offset;

                    if (tx_local < block_size) {
                        idx = tx_local;
                        array_offset = (offset + 1)*matrix_dim + offset;
                        for (i = 1; i < block_size; i++) {
                            m[array_offset + (bx_local + 1)*block_size + idx] = peri_row[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    } else {
                        idx = tx_local - block_size;
                        array_offset = (offset + (bx_local + 1)*block_size)*matrix_dim + offset;
                        for (i = 0; i < block_size; i++) {
                            m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                            array_offset += matrix_dim;
                        }
                    }
                }
            }
        }

        // lud_internal equivalent
        if (offset + block_size < matrix_dim) {
            int bx, by, tx, ty;
            int num_blocks_remaining = (matrix_dim - offset) / block_size - 1;
            if ((matrix_dim - offset) % block_size != 0) num_blocks_remaining++;

#pragma omp parallel for collapse(2) private(bx, by, tx, ty, i) shared(m, peri_row, peri_col, matrix_dim, offset, block_size)
            for (by = 0; by < num_blocks_remaining; by++) {
                for (bx = 0; bx < num_blocks_remaining; bx++) {
                    // Each work item corresponds to tx and ty in BLOCK_SIZE range
#pragma omp parallel for private(tx, ty, i) shared(m, peri_row, peri_col, matrix_dim, offset, bx, by, block_size)
                    for (ty = 0; ty < block_size; ty++) {
                        for (tx = 0; tx < block_size; tx++) {
                            int global_row_id = offset + (by + 1)*block_size;
                            int global_col_id = offset + (bx + 1)*block_size;

                            peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty)*matrix_dim + global_col_id + tx];
                            peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty)*matrix_dim + offset + tx];

                            // Barrier equivalent: no need due to single thread now, but we must accumulate sum correctly
                            float sum = 0;
                            for (i = 0; i < block_size; i++) {
                                sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                            }
                            m[(global_row_id + ty)*matrix_dim + global_col_id + tx] -= sum;
                        }
                    }
                }
            }
        }
    }

    free(shadow);
    free(peri_row);
    free(peri_col);
}
